import requests

def fetch_url(url):
    response = requests.get(url)
    if response.status_code == 200:
        print(response.text)
    else:
        print(f"Error fetching URL: {response.status_code}")

if __name__ == "__main__":
    url = input("Enter the URL: ")
    fetch_url(url)